#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e5 + 5;

int dfn[N], vis[N], low[N], dfncnt, ans[N], sz[N], n;

vector<int> e[N];

void tarjan(int u) {
    low[u] = dfn[u] = ++dfncnt, vis[u] = 1;
    bool flag = 0;
    int chd = 0, sum = 0, ss = n - 1;
    for (int v : e[u]) {
        if (!dfn[v]) {
            tarjan(v);
            sz[u] += sz[v];
            low[u] = min(low[u], low[v]);
            ++chd;
            if(low[v] >= dfn[u])
            {
            	flag = 1;
            	sum += sz[v] * (n - sz[v]);
            	ss -= sz[v];          	
            }
        } 
        else
            low[u] = min(low[u], dfn[v]);
    }
    if(u == 1 && chd < 2)
    	flag = 0;
    if(flag == 1)
    	ans[u] = n - 1 + ss * (n - ss) + sum;
    else ans[u] = 2 * (n - 1);
}

signed main() {
    int m;
    cin >> n >> m;
    for(int i = 1; i <= n; i++)
    {
    	sz[i] = 1;
    }
    for(int i = 1; i <= m; i++)
    {
    	int u, v;
    	cin >> u >> v;
    	e[u].push_back(v);
    	e[v].push_back(u);
    }
    tarjan(1);
    for(int i = 1; i <= n; i++)
    	cout << ans[i] << endl;

    return 0;
}
